INSERT INTO public.file_changes (id,ticket_id,session_id,event_id,file_name,file_path,label,summary,why,impact,change_kind,attribution_source,confidence,hunks,created_at,updated_at) VALUES ('eeeeeeee-0000-4000-8000-000000000001', 'bbbbbbbb-0000-4000-8000-000000000001', 'cccccccc-0000-4000-8000-000000000001', 'dddddddd-0000-4000-8000-000000000001', 'ci.yml', '.github/workflows/ci.yml', 'CI workflow updates', 'Added lint and test jobs with cached dependencies and fail-fast behavior.', 'This mirrors the first completed objective and gives the review card a concrete diff to inspect.', 'Improves pipeline feedback time and makes the review state feel like an in-progress deliverable.', 'modify', 'explicit', 'explicit', '[{"header":"@@ -1,8 +1,34 @@"}]', DEFAULT, DEFAULT), ('eeeeeeee-0000-4000-8000-000000000002', 'bbbbbbbb-0000-4000-8000-000000000001', 'cccccccc-0000-4000-8000-000000000001', 'dddddddd-0000-4000-8000-000000000001', 'deploy.yml', '.github/workflows/deploy.yml', 'Deploy workflow updates', 'Wired production secrets into the deploy job and gated releases on the main branch.', 'This mirrors the second completed objective and shows a second file in the same review batch.', 'Shows how the review ticket can carry multiple related file changes before merge.', 'modify', 'explicit', 'explicit', '[{"header":"@@ -0,0 +1,28 @@"}]', DEFAULT, DEFAULT);
INSERT INTO public.feed_posts (id,organization_id,project_id,ticket_id,session_id,agent_type,title,body,tags,impact_level,files_touched,tradeoffs,human_actions,source_event_ids,source_window_start,source_window_end,created_at,updated_at,tickets_created,objective_id,created_by) VALUES ('eb2f39ef-dbf0-5ca6-9c6e-bd28d6aedea8', 1, 'aaaaaaaa-0000-4000-8000-000000000001', 'bbbbbbbb-0000-4000-8000-000000000001', NULL, 'Veritur quae nihilii detractis quis possit integre, congressus satisti statimpedal consequam litter.', 'CI/CD pipeline scaffolded', 'Created the initial GitHub Actions workflows for linting and testing. Deployment step is stubbed pending secrets setup.', '{"ci","devops"}', 'medium', '{".github/workflows/ci.yml",".github/workflows/deploy.yml"}', '{"notes":"Used matrix builds for speed; increases parallel job costs."}', '{"Reviewed workflow config","Approved secrets plan"}', DEFAULT, '2020-07-11T18:47:32.000Z', '2020-08-20T19:29:35.000Z', DEFAULT, DEFAULT, '[]', NULL, NULL), ('28f2a137-3a27-550d-95fa-832ad097adfd', 1, 'aaaaaaaa-0000-4000-8000-000000000001', 'bbbbbbbb-0000-4000-8000-000000000002', NULL, 'Quod ut est nihiliores eos acut nihilesse.', 'Design tokens defined', 'Established the initial color palette and spacing scale. Typography tokens are pending font licensing confirmation.', '{"design","frontend"}', 'low', '{"tokens/colors.ts","tokens/spacing.ts"}', '{"notes":"Opted for CSS custom properties over JS-in-CSS for broader tooling compatibility."}', '{"Reviewed palette with design team"}', DEFAULT, '2020-08-16T08:07:23.000Z', '2020-03-07T02:40:34.000Z', DEFAULT, DEFAULT, '[]', NULL, NULL), ('b23c41a8-98c5-5998-aa1e-a9d63209dfc3', 1, 'aaaaaaaa-0000-4000-8000-000000000002', 'bbbbbbbb-0000-4000-8000-000000000004', NULL, 'Aret constituando non possimum probavitat deorum paritat quodsi, expressas morbis nos honore igam soleat ulla.', 'PostHog SDK integrated', 'Installed and initialized PostHog in the Beta app. Key flows (signup, onboarding, checkout) are now instrumented.', '{"analytics","tracking"}', 'medium', '{"lib/analytics.ts","app/layout.tsx"}', '{"notes":"Lazy-loaded the SDK to avoid blocking initial render."}', '{"Verified events in PostHog dashboard"}', DEFAULT, '2020-02-18T01:05:36.000Z', '2020-06-18T06:02:16.000Z', DEFAULT, DEFAULT, '[]', NULL, NULL), ('03001170-4b13-556d-a0ba-beccf9189e29', 1, 'aaaaaaaa-0000-4000-8000-000000000002', 'bbbbbbbb-0000-4000-8000-000000000005', NULL, 'Autemque causa eae sent appeterim, legenturum nec in quidque nullam.', 'Accessibility audit complete', 'Ran axe-core on all pages. Found 12 WCAG AA violations — 8 resolved, 4 deferred to next sprint pending design input.', '{"a11y","quality"}', 'high', '{"components/Button.tsx","components/Modal.tsx","app/page.tsx"}', '{"notes":"Deferred colour-contrast changes until brand refresh is finalised."}', '{"Triaged violations with design","Merged accessibility fixes"}', DEFAULT, '2020-03-19T02:39:08.000Z', '2020-10-10T21:24:11.000Z', DEFAULT, DEFAULT, '[]', NULL, NULL);
